$now = (Get-Date).ToUniversalTime()

# Start with everything retained; rule passes will move things into
# $toDelete. Doing it in this order keeps each rule independent and
# makes future rules easy to layer in.
$toDelete = New-Object System.Collections.Generic.List[object]
$retain   = New-Object System.Collections.Generic.List[object]
foreach ($a in $Artifacts) { [void]$retain.Add($a) }

# Rule: maxAgeDays — anything strictly older than the cutoff is deleted.
if ($Policy.ContainsKey('maxAgeDays')) {
    $maxAgeDays = [double]$Policy['maxAgeDays']
    $cutoff = $now.AddDays(-$maxAgeDays)
    $stillRetained = New-Object System.Collections.Generic.List[object]
    foreach ($a in $retain) {
        $created = [datetime]::Parse($a.createdAt).ToUniversalTime()
        if ($created -lt $cutoff) {
            [void]$toDelete.Add($a)
        } else {
            [void]$stillRetained.Add($a)
        }
    }
    $retain = $stillRetained
}

$toRetain = $retain.ToArray()
$toDelete = $toDelete.ToArray()

$retainedBytes = [long]0
foreach ($a in $toRetain) { $retainedBytes += [long]$a.size }
$reclaimedBytes = [long]0
foreach ($a in $toDelete) { $reclaimedBytes += [long]$a.size }

