# Rule: maxAgeDays — an artifact is considered "older than" maxAgeDays
# only if its full-day age exceeds maxAgeDays. Comparing on whole days
# avoids spurious deletions caused by sub-second drift between the
# caller's "now" and ours.
if ($Policy.ContainsKey('maxAgeDays')) {
    $maxAgeDays = [double]$Policy['maxAgeDays']
    $stillRetained = New-Object System.Collections.Generic.List[object]
    foreach ($a in $retain) {
        $created = [datetime]::Parse($a.createdAt).ToUniversalTime()
        $ageDays = [math]::Floor(($now - $created).TotalDays)
        if ($ageDays -gt $maxAgeDays) {
            [void]$toDelete.Add($a)
        } else {
            [void]$stillRetained.Add($a)
        }
    }
    $retain = $stillRetained
}

