            New-TestArtifact -Name 'a' -Size 100 -WorkflowRunId 'wf1' -CreatedAt $now.AddDays(-2)
            New-TestArtifact -Name 'b' -Size 100 -WorkflowRunId 'wf1' -CreatedAt $now.AddDays(-1)
