            maxTotalSize          = 50
            keepLatestPerWorkflow = 2
        }

        @($plan.toDelete).Count | Should -Be 0
        @($plan.toRetain).Count | Should -Be 2
        $plan.totalRetainedBytes | Should -Be 200
    }
}

