# Verify both jobs reported success — act prints "Job succeeded" or
# "Job failed" for each job.
foreach ($job in $ExpectedJobs) {
    # act prints job name with various decorations; we check that the
    # job appears AND that "Job succeeded" appears. Without per-job
    # parsing in act's output we use a global "no Job failed" check
    # plus a count of "Job succeeded" >= number of expected jobs.
    if ($log -notmatch [regex]::Escape($job)) {
        $failures.Add("[$caseName] act output never mentions job '$job'")
    }
}

$succeededCount = ([regex]::Matches($log, 'Job succeeded')).Count
if ($succeededCount -lt $ExpectedJobs.Count) {
    $failures.Add("[$caseName] expected at least $($ExpectedJobs.Count) 'Job succeeded' lines, found $succeededCount")
}
if ($log -match 'Job failed') {
    $failures.Add("[$caseName] act output contains 'Job failed'")
}

