input.command:
pwsh -NoProfile -Command "
\$result = Get-Content -Raw -LiteralPath ./act-result.txt
\$cases = @(
    @{ Name='case1-age';                Fixture='fixtures/case1-age.json' },
    @{ Name='case2-combined';           Fixture='fixtures/case2-combined.json' },
    @{ Name='case3-keeplatest-dryrun';  Fixture='fixtures/case3-keeplatest-dryrun.json' }
)
\$expectedJobNames = @('Pester unit tests', 'Run cleanup script against fixture')

# Split act-result.txt into per-case sections by the delimiter our harness wrote.
\$sections = \$result -split '={70,}\s*\nTEST CASE: '
\$failures = New-Object System.Collections.Generic.List[string]
foreach (\$case in \$cases) {
    \$section = \$sections | Where-Object { \$_ -match \"^\$(\$case.Name)\b\" } | Select-Object -First 1
    if (-not \$section) { \$failures.Add(\"missing section for \$(\$case.Name)\"); continue }
    \$expected = (Get-Content -Raw -LiteralPath \$case.Fixture | ConvertFrom-Json).expected
    if (\$section -notmatch 'ACT EXIT:\s+0') { \$failures.Add(\"\$(\$case.Name) act exit not 0\"); }
    foreach (\$jn in \$expectedJobNames) {
        if (\$section -notmatch [regex]::Escape(\$jn)) { \$failures.Add(\"\$(\$case.Name) missing job '\$jn'\") }
    }
    \$succ = ([regex]::Matches(\$section, 'Job succeeded')).Count
    if (\$succ -lt 2) { \$failures.Add(\"\$(\$case.Name) only \$succ Job succeeded (expected >=2)\") }
    if (\$section -match 'Job failed') { \$failures.Add(\"\$(\$case.Name) Job failed line present\") }
    foreach (\$key in @('deletedCount','retainedCount','totalReclaimedBytes','totalRetainedBytes','dryRun','mockDeletedActually')) {
        \$pat = \"ASSERT \$key=([^\`r\`n]+)\"
        if (\$section -match \$pat) {
            \$actual = \$Matches[1].Trim()
            \$exp = \"\$(\$expected.\$key)\"
            if (\$actual -ne \$exp) { \$failures.Add(\"\$(\$case.Name) \$key actual=\$actual expected=\$exp\") }
            else { Write-Host \"OK [\$(\$case.Name)] \$key = \$actual\" }
        } else {
            \$failures.Add(\"\$(\$case.Name) missing ASSERT for \$key\")
        }
    }
}
Write-Host ''
if (\$failures.Count -gt 0) {
    Write-Host \"FAILURES:\" -ForegroundColor Red
    foreach (\$f in \$failures) { Write-Host \"  - \$f\" -ForegroundColor Red }
    exit 1
}
Write-Host 'ALL OFFLINE ASSERTIONS PASS' -ForegroundColor Green
"
